# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import Optional
from pathlib import Path


class FileAccessControl:
    def __init__(self, db_path: str = "permissions.db"):
        self.db_path = db_path
        self._initialize_database()
    
    def _initialize_database(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS users (
                user_id INTEGER PRIMARY KEY,
                username TEXT UNIQUE NOT NULL,
                role TEXT NOT NULL
            )
        """)
        
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS files (
                file_id INTEGER PRIMARY KEY,
                filepath TEXT UNIQUE NOT NULL,
                owner_id INTEGER,
                required_permission TEXT NOT NULL,
                FOREIGN KEY (owner_id) REFERENCES users(user_id)
            )
        """)
        
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS permissions (
                permission_id INTEGER PRIMARY KEY,
                user_id INTEGER,
                file_id INTEGER,
                access_level TEXT NOT NULL,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id),
                UNIQUE(user_id, file_id)
            )
        """)
        
        conn.commit()
        conn.close()
    
    def add_user(self, username: str, role: str = "user") -> int:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute(
            "INSERT OR IGNORE INTO users (username, role) VALUES (?, ?)",
            (username, role)
        )
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_id = cursor.fetchone()[0]
        
        conn.commit()
        conn.close()
        
        return user_id
    
    def register_file(self, filepath: str, owner_username: str, required_permission: str = "read") -> int:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (owner_username,))
        result = cursor.fetchone()
        
        if not result:
            conn.close()
            raise ValueError(f"User {owner_username} not found")
        
        owner_id = result[0]
        
        cursor.execute(
            "INSERT OR IGNORE INTO files (filepath, owner_id, required_permission) VALUES (?, ?, ?)",
            (filepath, owner_id, required_permission)
        )
        
        cursor.execute("SELECT file_id FROM files WHERE filepath = ?", (filepath,))
        file_id = cursor.fetchone()[0]
        
        conn.commit()
        conn.close()
        
        return file_id
    
    def grant_permission(self, username: str, filepath: str, access_level: str = "read"):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        
        if not user_result:
            conn.close()
            raise ValueError(f"User {username} not found")
        
        cursor.execute("SELECT file_id FROM files WHERE filepath = ?", (filepath,))
        file_result = cursor.fetchone()
        
        if not file_result:
            conn.close()
            raise ValueError(f"File {filepath} not registered")
        
        user_id = user_result[0]
        file_id = file_result[0]
        
        cursor.execute(
            "INSERT OR REPLACE INTO permissions (user_id, file_id, access_level) VALUES (?, ?, ?)",
            (user_id, file_id, access_level)
        )
        
        conn.commit()
        conn.close()
    
    def revoke_permission(self, username: str, filepath: str):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute(
            """
            DELETE FROM permissions 
            WHERE user_id = (SELECT user_id FROM users WHERE username = ?)
            AND file_id = (SELECT file_id FROM files WHERE filepath = ?)
            """,
            (username, filepath)
        )
        
        conn.commit()
        conn.close()
    
    def check_permission(self, username: str, filepath: str, required_access: str = "read") -> bool:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id, role FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        
        if not user_result:
            conn.close()
            return False
        
        user_id, role = user_result
        
        if role == "admin":
            conn.close()
            return True
        
        cursor.execute("SELECT file_id, owner_id FROM files WHERE filepath = ?", (filepath,))
        file_result = cursor.fetchone()
        
        if not file_result:
            conn.close()
            return False
        
        file_id, owner_id = file_result
        
        if user_id == owner_id:
            conn.close()
            return True
        
        cursor.execute(
            """
            SELECT access_level FROM permissions 
            WHERE user_id = ? AND file_id = ?
            """,
            (user_id, file_id)
        )
        
        permission_result = cursor.fetchone()
        conn.close()
        
        if not permission_result:
            return False
        
        access_level = permission_result[0]
        
        access_hierarchy = {"read": 1, "write": 2, "admin": 3}
        
        user_level = access_hierarchy.get(access_level, 0)
        required_level = access_hierarchy.get(required_access, 0)
        
        return user_level >= required_level
    
    def read_file(self, username: str, filepath: str) -> Optional[str]:
        if not self.check_permission(username, filepath, "read"):
            raise PermissionError(f"User {username} does not have read permission for {filepath}")
        
        try:
            with open(filepath, 'r') as f:
                return f.read()
        except FileNotFoundError:
            raise FileNotFoundError(f"File {filepath} does not exist on disk")
        except Exception as e:
            raise IOError(f"Error reading file {filepath}: {str(e)}")
    
    def write_file(self, username: str, filepath: str, content: str):
        if not self.check_permission(username, filepath, "write"):
            raise PermissionError(f"User {username} does not have write permission for {filepath}")
        
        try:
            with open(filepath, 'w') as f:
                f.write(content)
        except Exception as e:
            raise IOError(f"Error writing to file {filepath}: {str(e)}")
    
    def list_user_files(self, username: str) -> list:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_result = cursor.fetchone()
        
        if not user_result:
            conn.close()
            return []
        
        user_id = user_result[0]
        
        cursor.execute(
            """
            SELECT DISTINCT f.filepath, p.access_level
            FROM files f
            JOIN permissions p ON f.file_id = p.file_id
            WHERE p.user_id = ?
            UNION
            SELECT filepath, 'owner' as access_level
            FROM files
            WHERE owner_id = ?
            """,
            (user_id, user_id)
        )
        
        files = cursor.fetchall()
        conn.close()
        
        return [{"filepath": f[0], "access_level": f[1]} for f in files]


